solutions.python:
class Solution:
    def countNumbersWithUniqueDigits(self, n: int) -> int:
        if n == 0: return 1
        ans, unique = 10, 9
        for i in range(2, n + 1):
            unique *= 11 - i
            ans += unique
        return ans

