class Solution {
public:
    int countNumbersWithUniqueDigits(int n) {
        if (n == 0) return 1;
        int ans = 10, unique = 9;
        for (int i = 2; i <= n; i++) { unique *= 11 - i; ans += unique; }
        return ans;
    }
};

